def max_shifts(shifts):
    if not shifts:
        return 0
    # Greedy: sort by end time, always pick the shift that finishes earliest
    sorted_shifts = sorted(shifts, key=lambda x: x[1])
    count = 1
    last_end = sorted_shifts[0][1]
    for i in range(1, len(sorted_shifts)):
        if sorted_shifts[i][0] >= last_end:
            count += 1
            last_end = sorted_shifts[i][1]
    return count

