import unittest

class TestSolution(unittest.TestCase):
    def test_example(self):
        shifts = [(1, 4), (3, 5), (0, 6), (5, 7), (8, 9), (5, 9)]
        self.assertEqual(max_shifts(shifts), 3)

    def test_all_compatible(self):
        shifts = [(1, 2), (3, 4), (5, 6)]
        self.assertEqual(max_shifts(shifts), 3)

    def test_all_overlapping(self):
        shifts = [(1, 5), (2, 6), (3, 7)]
        self.assertEqual(max_shifts(shifts), 1)

    def test_hidden_empty(self):
        self.assertEqual(max_shifts([]), 0)

    def test_hidden_single(self):
        self.assertEqual(max_shifts([(10, 20)]), 1)

    def test_hidden_adjacent_exact(self):
        shifts = [(1, 2), (2, 3), (3, 4), (4, 5)]
        self.assertEqual(max_shifts(shifts), 4)

    def test_hidden_nested_intervals(self):
        shifts = [(1, 10), (2, 3), (4, 5), (6, 7)]
        self.assertEqual(max_shifts(shifts), 3)

    def test_hidden_same_end_time(self):
        shifts = [(1, 5), (2, 5), (3, 5), (5, 8)]
        self.assertEqual(max_shifts(shifts), 2)

    def test_hidden_large_values(self):
        shifts = [(0, 1000000000), (500000000, 999999999)]
        self.assertEqual(max_shifts(shifts), 1)

    def test_hidden_large_input(self):
        # 1000 non-overlapping shifts
        shifts = [(i * 2, i * 2 + 1) for i in range(1000)]
        self.assertEqual(max_shifts(shifts), 1000)

    def test_hidden_reverse_order(self):
        # Shifts given in reverse order of end time
        shifts = [(8, 10), (5, 7), (2, 4), (0, 1)]
        self.assertEqual(max_shifts(shifts), 4)

if __name__ == '__main__':
    unittest.main()
